import{_ as t,o as r,c as n,ag as a}from"./chunks/framework.5wcOFaQl.js";const h=JSON.parse('{"title":"Software Development, Web Development & Yuanbao 💻🌐💰","description":"","frontmatter":{},"headers":[],"relativePath":"skills/dev-web-yuanbao.md","filePath":"skills/dev-web-yuanbao.md"}'),i={name:"skills/dev-web-yuanbao.md"};function s(o,e,d,l,g,u){return r(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="software-development-web-development-yuanbao-💻🌐💰" tabindex="-1">Software Development, Web Development &amp; Yuanbao 💻🌐💰 <a class="header-anchor" href="#software-development-web-development-yuanbao-💻🌐💰" aria-label="Permalink to &quot;Software Development, Web Development &amp; Yuanbao 💻🌐💰&quot;">​</a></h1><hr><h2 id="💻-software-development" tabindex="-1">💻 Software Development <a class="header-anchor" href="#💻-software-development" aria-label="Permalink to &quot;💻 Software Development&quot;">​</a></h2><p>Skills für Entwickler: Debugging, TDD, Code-Review, Plans und mehr.</p><table tabindex="0"><thead><tr><th>Skill</th><th>Beschreibung</th></tr></thead><tbody><tr><td><strong>debugging-hermes-tui-commands</strong></td><td>Hermes TUI Slash-Befehle debuggen</td></tr><tr><td><strong>flask-script-dashboard</strong></td><td>Python-Skripte wrappen (1:1!) als Flask-Dashboard</td></tr><tr><td><strong>game-guide-vitepress</strong></td><td>Spielguide/Compendium als VitePress-Webseite</td></tr><tr><td><strong>hermes-agent-skill-authoring</strong></td><td>Eigene SKILL.md schreiben: Frontmatter, Validator, Struktur</td></tr><tr><td><strong>node-inspect-debugger</strong></td><td>Node.js via --inspect + Chrome DevTools Protocol debuggen</td></tr><tr><td><strong>plan</strong></td><td>Plan-Modus: Markdown-Plan schreiben, keine Ausführung</td></tr><tr><td><strong>python-debugpy</strong></td><td>Python debuggen: pdb REPL + debugpy remote (DAP)</td></tr><tr><td><strong>python-script-to-package</strong></td><td>Verstreute Python-Skripte in installierbares Paket umstrukturieren</td></tr><tr><td><strong>requesting-code-review</strong></td><td>Pre-Commit-Review: Security-Scan, Quality Gates, Auto-Fix</td></tr><tr><td><strong>subagent-driven-development</strong></td><td>Implementierungspläne mit unabhängigen Sub-Agenten ausführen</td></tr><tr><td><strong>systematic-debugging</strong></td><td>Systematisches Debuggen: bei jedem Bug/Test-Fehler</td></tr><tr><td><strong>test-driven-development</strong></td><td>TDD: RED-GREEN-REFACTOR, Tests vor Code</td></tr><tr><td><strong>web-based-admin-panel</strong></td><td>Webbasiertes Server-Admin-Panel (Webmin-ähnlich)</td></tr><tr><td><strong>writing-plans</strong></td><td>Implementierungspläne schreiben: kleine Tasks, Pfade, Code</td></tr></tbody></table><h3 id="🎯-wichtige-skills-im-detail" tabindex="-1">🎯 Wichtige Skills im Detail <a class="header-anchor" href="#🎯-wichtige-skills-im-detail" aria-label="Permalink to &quot;🎯 Wichtige Skills im Detail&quot;">​</a></h3><h4 id="systematic-debugging" tabindex="-1">systematic-debugging <a class="header-anchor" href="#systematic-debugging" aria-label="Permalink to &quot;systematic-debugging&quot;">​</a></h4><p><strong>Auslöser:</strong> „Das Programm stürzt ab&quot;, „Stacktrace&quot;, „Debug den Fehler&quot;</p><p>Der wichtigste Debug-Skill. Bei jedem Bug oder Test-Fehler wird systematisch vorgegangen:</p><ol><li>Fehler reproduzieren</li><li>Minimales Beispiel isolieren</li><li>Logs/Stacktrace analysieren</li><li>Hypothese bilden</li><li>Fix implementieren</li><li>Testen, ob Fix wirkt</li><li>Regression-Tests laufen lassen</li></ol><h4 id="test-driven-development" tabindex="-1">test-driven-development <a class="header-anchor" href="#test-driven-development" aria-label="Permalink to &quot;test-driven-development&quot;">​</a></h4><p><strong>Auslöser:</strong> „TDD&quot;, „Test first&quot;, „RED-GREEN-REFACTOR&quot;</p><p>Zwingt zum Test-first-Ansatz:</p><ol><li><strong>RED</strong> – Test schreiben, der fehlschlägt</li><li><strong>GREEN</strong> – Code schreiben, der Test bestehen lässt</li><li><strong>REFACTOR</strong> – Code verbessern, Tests bleiben grün</li></ol><h4 id="writing-plans-plan" tabindex="-1">writing-plans &amp; plan <a class="header-anchor" href="#writing-plans-plan" aria-label="Permalink to &quot;writing-plans &amp; plan&quot;">​</a></h4><p><strong>Auslöser:</strong> „Plan erstellen&quot;, „Task-Liste&quot;, „Vorgehen planen&quot;</p><p>Diese Skills erstellen detaillierte Implementierungspläne, bevor Code geschrieben wird. <code>plan</code> schreibt den Plan nur (keine Ausführung), <code>writing-plans</code> erstellt Task-Listen mit Pfaden und Code-Schnipseln.</p><h4 id="requesting-code-review" tabindex="-1">requesting-code-review <a class="header-anchor" href="#requesting-code-review" aria-label="Permalink to &quot;requesting-code-review&quot;">​</a></h4><p><strong>Auslöser:</strong> „Review meinen Code&quot;, „Security-Check&quot;, „Code-Qualität&quot;</p><p>Führt vor dem Commit eine automatisierte Code-Review durch: Security-Scan, Quality Gates (Linter, Type-Checker), Style-Prüfung und Auto-Fix für einfache Probleme.</p><h4 id="flask-script-dashboard" tabindex="-1">flask-script-dashboard <a class="header-anchor" href="#flask-script-dashboard" aria-label="Permalink to &quot;flask-script-dashboard&quot;">​</a></h4><p><strong>Auslöser:</strong> „Dashboard für Python-Skript&quot;, „Web-GUI für CLI-Tool&quot;</p><p>Wrapt bestehende Python-Skripte in ein Flask-Web-Dashboard. Wichtig: Die Orginal-Skripte werden <strong>nie verändert</strong> (1:1-Kopie-Prinzip).</p><h4 id="python-debugpy" tabindex="-1">python-debugpy <a class="header-anchor" href="#python-debugpy" aria-label="Permalink to &quot;python-debugpy&quot;">​</a></h4><p><strong>Auslöser:</strong> „Python Debugger&quot;, „pdb&quot;, „debugpy&quot;</p><p>Startet eine Python-Debug-Session mit pdb oder debugpy (DAP-Protokoll). Ermöglicht Step-Debugging, Breakpoints, Variable-Inspection.</p><hr><h2 id="🌐-web-development" tabindex="-1">🌐 Web Development <a class="header-anchor" href="#🌐-web-development" aria-label="Permalink to &quot;🌐 Web Development&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Skill</th><th>Beschreibung</th></tr></thead><tbody><tr><td><strong>vitepress-github-pages</strong></td><td>VitePress-Projekt einrichten + auf GitHub Pages deployen</td></tr><tr><td><strong>wwm-compendium</strong></td><td>Fan-Wiki für Where Winds Meet (WWM) – VitePress-Projekt</td></tr></tbody></table><h3 id="vitepress-github-pages" tabindex="-1">vitepress-github-pages <a class="header-anchor" href="#vitepress-github-pages" aria-label="Permalink to &quot;vitepress-github-pages&quot;">​</a></h3><p><strong>Auslöser:</strong> „Neue VitePress-Seite&quot;, „GitHub Pages Setup&quot;, „Dokumentationsseite&quot;</p><p>Richtet ein VitePress-Projekt ein und deployt es auf GitHub Pages. Kompletter Workflow: Projekt initialisieren, konfigurieren, Theme anpassen, CI/CD-Workflow erstellen, Repo anlegen.</p><h3 id="wwm-compendium" tabindex="-1">wwm-compendium <a class="header-anchor" href="#wwm-compendium" aria-label="Permalink to &quot;wwm-compendium&quot;">​</a></h3><p><strong>Auslöser:</strong> „WWM-Seite bearbeiten&quot;, „Where Winds Meet&quot;</p><p>Das Fan-Wiki für Where Winds Meet, ebenfalls mit VitePress gebaut. Ca. 45 Seiten: Waffen, Bosse, Quests, Items, Info.</p><hr><h2 id="💰-yuanbao" tabindex="-1">💰 Yuanbao <a class="header-anchor" href="#💰-yuanbao" aria-label="Permalink to &quot;💰 Yuanbao&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Skill</th><th>Beschreibung</th></tr></thead><tbody><tr><td><strong>yuanbao</strong></td><td>Yuanbao (元宝) Gruppen: @mention, Info/Members abfragen</td></tr></tbody></table><p><strong>Auslöser:</strong> „Yuanbao-Gruppe&quot;, „元宝&quot;, „Mitglieder abfragen&quot;</p><p>Ermöglicht Interaktion mit Yuanbao-Gruppen: Mitglieder @erwähnen, Gruppeninfo abfragen, Mitgliederliste holen. Yuanbao ist eine chinesische Messaging-Plattform.</p>',40)])])}const b=t(i,[["render",s]]);export{h as __pageData,b as default};
